async () => {
  const b64 = "";
  // decode base64 to binary string then to utf8
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  const script = new TextDecoder().decode(bytes);

  const kvId = "d35f6899238d43438a59837160900db7";
  const vapidPublic = "BDOHuJxy-7QveDgDGewF8cj3b9zMjuTl3lpwEfZfjdfvhXvMKJ7Sukc1iQXZMgnmxJrisOdarHQGUMQMAm2OzIo";
  const vapidPrivate = "G5xV5j-qbA9YqdJ_z0g5bhcf5_xqa91Z4s52Iqb2ktg";
  const vapidSubject = "mailto:bitachon@example.com";
  const adminToken = "bitachon-admin-G5xV5j-q";
  const appUrl = "https://eli2109.github.io/sagesse-bitachon/";

  const metadata = {
    main_module: "worker.js",
    compatibility_date: "2026-01-01",
    bindings: [
      { type: "kv_namespace", name: "SUBSCRIPTIONS", namespace_id: kvId },
      { type: "plain_text", name: "VAPID_PUBLIC_KEY", text: vapidPublic },
      { type: "plain_text", name: "VAPID_SUBJECT", text: vapidSubject },
      { type: "plain_text", name: "APP_URL", text: appUrl },
    ],
  };

  const boundary = "----CFWorkerForm" + Date.now();
  const body = [
    "--" + boundary,
    'Content-Disposition: form-data; name="metadata"',
    "Content-Type: application/json",
    "",
    JSON.stringify(metadata),
    "--" + boundary,
    'Content-Disposition: form-data; name="worker.js"; filename="worker.js"',
    "Content-Type: application/javascript+module",
    "",
    script,
    "--" + boundary + "--",
    "",
  ].join("\r\n");

  const upload = await cloudflare.request({
    method: "PUT",
    path: `/accounts/${accountId}/workers/scripts/sagesse-bitachon-push`,
    body,
    contentType: `multipart/form-data; boundary=${boundary}`,
    rawBody: true,
  });

  if (!upload.success) {
    return { step: "upload", success: false, status: upload.status, errors: upload.errors, messages: upload.messages, result: upload.result };
  }

  const sec1 = await cloudflare.request({
    method: "PUT",
    path: `/accounts/${accountId}/workers/scripts/sagesse-bitachon-push/secrets`,
    body: { name: "VAPID_PRIVATE_KEY", text: vapidPrivate, type: "secret_text" },
  });
  const sec2 = await cloudflare.request({
    method: "PUT",
    path: `/accounts/${accountId}/workers/scripts/sagesse-bitachon-push/secrets`,
    body: { name: "ADMIN_TOKEN", text: adminToken, type: "secret_text" },
  });

  const sub = await cloudflare.request({
    method: "POST",
    path: `/accounts/${accountId}/workers/scripts/sagesse-bitachon-push/subdomain`,
    body: { enabled: true },
  });

  const sched = await cloudflare.request({
    method: "PUT",
    path: `/accounts/${accountId}/workers/scripts/sagesse-bitachon-push/schedules`,
    body: [{ cron: "0 */3 * * *" }],
  });

  return {
    step: "done",
    upload_ok: upload.success,
    script_len: script.length,
    secrets: { vapid: sec1.success, admin: sec2.success, vapid_errors: sec1.errors, admin_errors: sec2.errors },
    subdomain: sub.result ?? sub,
    schedules: sched.result ?? sched,
    url: "https://sagesse-bitachon-push.eliahou-ae1.workers.dev",
  };
}